function sqlEscape(s) { return String(s).replace(/'/g, "''"); }
function jsonArr(arr) { return sqlEscape(JSON.stringify(arr)); }

let out = "-- Auto-generated by generate_pedagogy.mjs\n";
out += "-- 240 cells: 60 indicators × 4 levels (Marshall Rubric)\n\n";

let count = 0;
for (let id = 1; id <= 60; id++) {
  for (const level of [4, 3, 2, 1]) {
    const c = LIB[id] && LIB[id][level];
    if (!c) {
      console.error(`MISSING CELL: indicator ${id}, level ${level}`);
      process.exit(1);
    }
    out += `INSERT OR IGNORE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (${id}, ${level}, '${sqlEscape(c.interpretation)}', '${jsonArr(c.evidence_signals)}', '${jsonArr(c.teacher_next_moves)}', '${jsonArr(c.coaching_considerations)}', '${jsonArr(c.resources)}', '${sqlEscape(c.feedback_starter)}');\n`;
    count++;
  }
}

